import { type LeaveCoveredStatus, leaveEnumLabels, type LeaveStatus } from '@/api/leaveService';

type StatusKind = 'leave' | 'coverage';
type StatusSize = 'sm' | 'md';

interface WorkflowStatusChipProps {
    kind: StatusKind;
    value: LeaveStatus | LeaveCoveredStatus | number | string | null | undefined;
    size?: StatusSize;
    className?: string;
}

const SIZE_CLASS: Record<StatusSize, string> = {
    sm: 'px-2 py-0.5 text-xs',
    md: 'px-2.5 py-1 text-sm',
};

const LEAVE_STATUS_CLASS: Partial<Record<string, string>> = {
    Submitted:   'bg-sky-50 text-sky-700 border-sky-200 dark:bg-sky-950/60 dark:text-sky-300 dark:border-sky-800',
    Approved:    'bg-emerald-50 text-emerald-700 border-emerald-200 dark:bg-emerald-950/60 dark:text-emerald-300 dark:border-emerald-800',
    Rejected:    'bg-rose-50 text-rose-700 border-rose-200 dark:bg-rose-950/60 dark:text-rose-300 dark:border-rose-800',
    Consumed:    'bg-primary/10 text-primary border-primary/20',
    NotConsumed: 'bg-amber-50 text-amber-700 border-amber-200 dark:bg-amber-950/60 dark:text-amber-300 dark:border-amber-800',
    Finalized:   'bg-muted text-muted-foreground border-border',
};

const COVERAGE_STATUS_CLASS: Partial<Record<string, string>> = {
    Open:      'bg-muted text-muted-foreground border-border',
    Assigned:  'bg-primary/10 text-primary border-primary/20',
    Accepted:  'bg-violet-50 text-violet-700 border-violet-200 dark:bg-violet-950/60 dark:text-violet-300 dark:border-violet-800',
    Verified:  'bg-emerald-50 text-emerald-700 border-emerald-200 dark:bg-emerald-950/60 dark:text-emerald-300 dark:border-emerald-800',
    Cancelled: 'bg-rose-50 text-rose-700 border-rose-200 dark:bg-rose-950/60 dark:text-rose-300 dark:border-rose-800',
};

const FALLBACK_CLASS = 'bg-muted text-muted-foreground border-border';

function getLabel(kind: StatusKind, value: WorkflowStatusChipProps['value']): string {
    const str = String(value ?? '');
    if (kind === 'leave') {
        return leaveEnumLabels.leaveStatus[str as LeaveStatus] ?? (str || 'Unknown');
    }
    return leaveEnumLabels.leaveCoveredStatus[str as LeaveCoveredStatus] ?? (str || 'Unknown');
}

export function WorkflowStatusChip({ kind, value, size = 'md', className = '' }: WorkflowStatusChipProps) {
    const str = value == null ? null : String(value);
    const label = getLabel(kind, value);
    const colorMap = kind === 'leave' ? LEAVE_STATUS_CLASS : COVERAGE_STATUS_CLASS;
    const toneClass = (str != null ? colorMap[str] : undefined) ?? FALLBACK_CLASS;

    return (
        <span
            className={`inline-flex items-center rounded-full border font-semibold tracking-tight ${SIZE_CLASS[size]} ${toneClass} ${className}`}
            title={label}
        >
            {label}
        </span>
    );
}

interface LeaveStatusChipProps {
    value: LeaveStatus | number | string | null | undefined;
    size?: StatusSize;
    className?: string;
}

export function LeaveStatusChip({ value, size = 'md', className }: LeaveStatusChipProps) {
    return <WorkflowStatusChip kind="leave" value={value} size={size} className={className} />;
}

interface LeaveCoveredStatusChipProps {
    value: LeaveCoveredStatus | number | string | null | undefined;
    size?: StatusSize;
    className?: string;
}

export function LeaveCoveredStatusChip({ value, size = 'md', className }: LeaveCoveredStatusChipProps) {
    return <WorkflowStatusChip kind="coverage" value={value} size={size} className={className} />;
}
