import React, { useState } from 'react';
import {
  ClipboardList,
  Wallet,
  Users,
  Settings2,
  CalendarX
} from 'lucide-react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { userService as accountService } from '@/api/auth/userService';
import { leaveService } from '@/api/leaveService';
import { leaveQueryKeys } from '@/features/leave-management/hooks/leaveHooks';
import { LeaveRequestModal } from '@/features/leave-management/components/LeaveRequestModal';
import { type LeaveCreateForm } from '@/features/leave-management/types/leave-types';
import LeaveRequests from '@/features/leave-management/components/LeaveRequests';
import LeaveBalance from '@/features/leave-management/components/LeaveBalance';
import LeaveCoverage from '@/features/leave-management/components/LeaveCoverage';
import LeaveStructure from '@/features/leave-management/components/LeaveStructure';
import { PermissionGate } from '@/components/shared/PermissionGate';
import { PERMISSIONS } from '@/constants/permissions';
import { useAuth } from '@/shared/AuthContext';
import { Button } from '@/shadcn/components/ui/button';
import { Tabs, TabsList, TabsTrigger } from '@/shadcn/components/ui/tabs';
import { toast } from 'sonner';

type LeaveTab = 'requests' | 'balance' | 'coverage' | 'structure';

export default function LeaveManagement() {
  const queryClient = useQueryClient();
  const { hasPermission, user } = useAuth();

  const allTabs: { id: LeaveTab; label: string; icon: React.ElementType; permission: string }[] = [
    { id: 'requests', label: 'Leave Requests', icon: ClipboardList, permission: PERMISSIONS.Leave.Read },
    { id: 'balance', label: 'Balance & Ledger', icon: Wallet, permission: PERMISSIONS.LeaveBalance.Read },
    { id: 'coverage', label: 'Team Coverage', icon: Users, permission: PERMISSIONS.LeaveCovered.Read },
    { id: 'structure', label: 'Policy & Structure', icon: Settings2, permission: PERMISSIONS.LeaveStructure.Read }
  ];

  const allowedTabs = allTabs.filter(t => hasPermission(t.permission));
  const [activeTab, setActiveTab] = useState<LeaveTab>(allowedTabs[0]?.id || 'requests');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [userIdFilter, setUserIdFilter] = useState<string>('');

  const employeesQuery = useQuery({
    queryKey: ['leave-management-employees'],
    queryFn: () => accountService.getEmployees(),
  });

  const internsQuery = useQuery({
    queryKey: ['leave-management-interns'],
    queryFn: () => accountService.getInterns(),
  });

  const employeeOptions = React.useMemo(() => {
    const employees = Array.isArray(employeesQuery.data) ? employeesQuery.data : [];
    const interns = Array.isArray(internsQuery.data) ? internsQuery.data : [];

    const combined = [
      ...employees.map((e) => ({
        id: String(e.userProfileId || e.id),
        name: e.fullName || e.name || 'Unknown Employee'
      })),
      ...interns.map((i) => ({
        id: String(i.userProfileId || i.id),
        name: i.fullName || i.name || 'Unknown Intern'
      }))
    ];

    return Array.from(new Map(combined.filter(e => e.id).map(item => [item.id, item])).values());
  }, [employeesQuery.data, internsQuery.data]);

  const createLeaveMutation = useMutation({
    mutationFn: (form: LeaveCreateForm) => leaveService.leaves.create(form),
    onSuccess: async () => {
      setIsModalOpen(false);
      toast.success('Leave request submitted successfully!');
      setActiveTab('requests');
      setUserIdFilter('');

      await queryClient.invalidateQueries({ queryKey: leaveQueryKeys.all });
      await queryClient.invalidateQueries({ queryKey: ['leave-stats'] });
    },
  });

  return (
    <div className="page-wrapper flex flex-col" style={{ gap: 'var(--section-padding)' }}>
      <div className="page-header">
        <div className="flex items-center gap-3">
          <div className="size-12 flex items-center justify-center rounded-(--radius-lg) bg-primary/10 shrink-0">
            <CalendarX className="w-7 h-7 text-primary" />
          </div>
          <div>
            <h1 className="page-title">Leave Management</h1>
            <p className="page-subtitle">Manage leave requests, balances, team coverage, and policy</p>
          </div>
        </div>
        <Button onClick={() => setIsModalOpen(true)}>
          <ClipboardList className="w-3.5 h-3.5" />
          Request Leave
        </Button>
      </div>

      <Tabs value={activeTab} onValueChange={(v) => setActiveTab(v as LeaveTab)}>
        <TabsList variant="line">
          {allowedTabs.map((tab) => {
            const Icon = tab.icon;
            return (
              <TabsTrigger key={tab.id} value={tab.id}>
                <Icon className="w-3.5 h-3.5" />
                {tab.label}
              </TabsTrigger>
            );
          })}
        </TabsList>
      </Tabs>

      {activeTab === 'requests' && (
        <LeaveRequests
          externalUserIdFilter={userIdFilter}
          onUserIdFilterChange={setUserIdFilter}
          employeeOptions={employeeOptions}
        />
      )}
      {activeTab === 'balance' && <LeaveBalance />}
      {activeTab === 'coverage' && <LeaveCoverage />}
      {activeTab === 'structure' && (
        <PermissionGate permission={PERMISSIONS.LeaveStructure.Read}>
          <LeaveStructure />
        </PermissionGate>
      )}

      <LeaveRequestModal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onSubmit={(form) => createLeaveMutation.mutate(form)}
        isSubmitting={createLeaveMutation.isPending}
        initialUserId={user?.id || ''}
      />
    </div>
  );
}
