                    className="w-full px-4 py-2.5 bg-muted/50 border border-border rounded-lg text-xs font-bold text-foreground focus:bg-background focus:ring-4 focus:ring-primary/10 focus:border-primary transition-all outline-none appearance-none cursor-pointer"
