import { useMutation, useQueryClient } from '@tanstack/react-query';
import { useState } from 'react';
import { AlertCircle, CheckCircle2, Loader2, Ban } from 'lucide-react';
import { LeaveStatusChip } from '@/components/shared/WorkflowStatusChip';
import { leaveEnumLabels, leaveService, getLeaveErrorMessage } from '@/api/leaveService';
import { leaveQueryKeys, useLeaveDetailQuery } from '@/features/leave-management/hooks/leaveHooks';
import { formatDate, type LeaveEditForm } from '../types/leave-types';
import { HarmonyDialog } from "@/components/ui/harmony-dialog";
import { Button } from "@/shadcn/components/ui/button";
import HarmonyForm from "@/components/forms/HarmonyForm";


// ── REJECT MODAL ──────────────────────────────────────────────────────────

interface RejectLeaveModalProps {
    open: boolean;
    onCancel: () => void;
    onConfirm: (formData: Record<string, unknown>) => void;
    isLoading: boolean;
}

export function RejectLeaveModal({
    open,
    onCancel,
    onConfirm,
    isLoading,
}: RejectLeaveModalProps) {
    return (
        <HarmonyDialog
            open={open}
            onOpenChange={onCancel}
            title="Reject Leave Request"
            description="Specify the reason for rejection"
            footerChildren={
                <div className="flex justify-end gap-3 w-full">
                    <Button variant="secondary" onClick={onCancel} disabled={isLoading}>Cancel</Button>
                    <Button variant="destructive" disabled={isLoading} type="button" onClick={() => document.querySelector("form")?.requestSubmit?.()}>
                        {isLoading && <Loader2 className="w-4 h-4 animate-spin" />}
                        Confirm Rejection
                    </Button>
                </div>
            }
        >
            <div className="space-y-5">
                <div className="bg-destructive/10 border border-destructive/20 p-4 rounded-2xl flex gap-3">
                    <Ban className="w-4 h-4 text-destructive shrink-0 mt-0.5" />
                    <p className="text-[11px] font-medium text-destructive leading-relaxed">
                        Rejection notes are mandatory and will be shared with the employee for transparency.
                    </p>
                </div>
                <HarmonyForm
                    dtoName="LeaveRejectDTO"
                    mode="create"
                    onSubmit={onConfirm}
                    isPending={isLoading}
                    hideSubmitButton
                />
            </div>
        </HarmonyDialog>
    );
}

// ── EDIT MODAL ────────────────────────────────────────────────────────────

interface EditLeaveModalProps {
    data: LeaveEditForm | null;
    onClose: () => void;
    onSuccess: () => void;
}

export function EditLeaveModal({
    data,
    onClose,
    onSuccess,
}: EditLeaveModalProps) {
    const queryClient = useQueryClient();
    const [error, setError] = useState('');

    const mutation = useMutation({
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        mutationFn: (formData: any) =>
            leaveService.leaves.update(data!.id, {
                leaveSize: formData.LeaveSize,
                leaveType: formData.LeaveType,
                reason: formData.Reason,
                notes: formData.Notes || null,
            }),
        onSuccess: async () => {
            await queryClient.invalidateQueries({ queryKey: leaveQueryKeys.all });
            onSuccess();
            onClose();
        },
        onError: (err) => setError(getLeaveErrorMessage(err)),
    });

    if (!data) return null;

    return (
        <HarmonyDialog
            open={Boolean(data)}
            onOpenChange={onClose}
            title="Edit Leave Request"
            description="Modify the details of your submitted request"
            footerChildren={
                <div className="flex justify-end gap-3 w-full">
                    <Button variant="secondary" onClick={onClose} disabled={mutation.isPending}>Cancel</Button>
                    <Button disabled={mutation.isPending} type="button" onClick={() => document.querySelector("form")?.requestSubmit?.()}>
                        {mutation.isPending && <Loader2 className="w-4 h-4 animate-spin" />}
                        Save Changes
                    </Button>
                </div>
            }
        >
            <div className="space-y-6">
                {error && (
                    <div className="bg-destructive/10 border border-destructive/20 p-4 rounded-2xl flex gap-3 animate-in fade-in slide-in-from-top-2">
                        <AlertCircle className="w-4 h-4 text-destructive shrink-0 mt-0.5" />
                        <p className="text-[11px] font-bold text-destructive">{error}</p>
                    </div>
                )}
                <HarmonyForm
                    dtoName="LeaveUpdateDTO"
                    mode="edit"
                    initialValues={{
                        LeaveSize: data.leaveSize,
                        LeaveType: data.leaveType,
                        Reason: data.reason,
                        Notes: data.notes,
                    }}
                    onSubmit={(formData) => mutation.mutate(formData)}
                    isPending={mutation.isPending}
                    hideSubmitButton
                />
            </div>
        </HarmonyDialog>
    );
}

// ── DETAIL DRAWER ─────────────────────────────────────────────────────────

interface LeaveDetailModalProps {
    id: string | null;
    onClose: () => void;
}

export function LeaveDetailModal({ id, onClose }: LeaveDetailModalProps) {
    const { data: leave, isLoading, error } = useLeaveDetailQuery(id || '', {
        enabled: Boolean(id),
    });

    return (
        <HarmonyDialog
            open={Boolean(id)}
            onOpenChange={onClose}
            title="Leave Details"
            description="Full history and status of this request"
            showFooter={false}
        >
            <div className="space-y-8">
                {isLoading && (
                    <div className="flex flex-col items-center justify-center py-20 gap-4">
                        <Loader2 className="w-10 h-10 text-primary animate-spin" />
                        <p className="text-xs font-black text-muted-foreground uppercase tracking-widest">Retrieving Data...</p>
                    </div>
                )}

                {error && (
                    <div className="bg-destructive/10 border border-destructive/20 p-6 rounded-[28px] flex flex-col items-center text-center gap-3">
                        <AlertCircle className="w-10 h-10 text-destructive" />
                        <p className="text-sm font-bold text-destructive">{getLeaveErrorMessage(error)}</p>
                    </div>
                )}

                {leave && (
                    <div className="space-y-8 animate-in fade-in slide-in-from-right-4 duration-500">
                        <div className="flex items-center justify-between p-5 bg-muted/50 rounded-[28px] border border-border">
                            <div className="space-y-1">
                                <p className="text-[10px] font-black uppercase tracking-widest text-muted-foreground">Current Status</p>
                                <div className="pt-1"><LeaveStatusChip value={leave.status} /></div>
                            </div>
                            <div className="text-right space-y-1">
                                <p className="text-[10px] font-black uppercase tracking-widest text-muted-foreground">Requested For</p>
                                <p className="text-sm font-black text-foreground tracking-tight">{formatDate(leave.leaveDate)}</p>
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div className="p-5 bg-card border border-border rounded-[28px] shadow-sm">
                                <p className="text-[10px] font-black uppercase tracking-widest text-muted-foreground">Policy Type</p>
                                <p className="mt-1.5 text-sm font-black text-foreground tracking-tight">{leaveEnumLabels.leaveType[leave.leaveType]}</p>
                            </div>
                            <div className="p-5 bg-card border border-border rounded-[28px] shadow-sm">
                                <p className="text-[10px] font-black uppercase tracking-widest text-muted-foreground">Leave Size</p>
                                <p className="mt-1.5 text-sm font-black text-foreground tracking-tight">{leaveEnumLabels.leaveSize[leave.leaveSize]}</p>
                            </div>
                        </div>

                        <div className="space-y-3">
                            <label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground ml-1">Application Reason</label>
                            <div className="p-6 bg-muted/50 rounded-[28px] border border-border">
                                <p className="text-sm font-bold text-foreground leading-relaxed italic">"{leave.reason}"</p>
                            </div>
                        </div>

                        {leave.notes && (
                            <div className="space-y-3">
                                <label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground ml-1">Additional Context</label>
                                <div className="p-6 bg-card border border-border rounded-[28px] shadow-sm">
                                    <p className="text-xs font-medium text-muted-foreground leading-relaxed">{leave.notes}</p>
                                </div>
                            </div>
                        )}

                        {leave.rejectionNotes && (
                            <div className="p-6 bg-rose-50 dark:bg-rose-950/30 rounded-[28px] border border-rose-100 dark:border-rose-800 relative overflow-hidden group">
                                <Ban className="absolute -right-4 -bottom-4 w-24 h-24 text-rose-100/50 dark:text-rose-800/50 -rotate-12 transition-transform group-hover:scale-110" />
                                <p className="text-[10px] font-black uppercase tracking-widest text-rose-600 dark:text-rose-400 mb-2">Rejection Feedback</p>
                                <p className="text-sm font-black text-rose-900 dark:text-rose-200 leading-relaxed relative z-10">{leave.rejectionNotes}</p>
                            </div>
                        )}

                        {leave.approvedOn && (
                            <div className="p-5 bg-primary/5 rounded-[24px] border border-primary/20 flex items-center justify-between">
                                <div className="flex items-center gap-3">
                                    <div className="w-8 h-8 rounded-lg bg-primary flex items-center justify-center">
                                        <CheckCircle2 className="w-4 h-4 text-primary-foreground" />
                                    </div>
                                    <div>
                                        <p className="text-[10px] font-black uppercase tracking-widest text-primary">System Approval</p>
                                        <p className="text-xs font-bold text-foreground">{formatDate(leave.approvedOn)}</p>
                                    </div>
                                </div>
                                {leave.approvedByUserId && (
                                    <span className="text-[10px] font-black text-muted-foreground uppercase tracking-widest">Ref: {leave.approvedByUserId.slice(0, 8)}</span>
                                )}
                            </div>
                        )}
                    </div>
                )}
            </div>
        </HarmonyDialog>
    );
}
