import { useMemo, useState } from 'react';
import { LeaveStatus, type LeaveListParams, LeaveType } from '@/api/leaveService';

interface UseLeaveRequestFiltersProps {
    externalUserId?: string;
    onExternalUserChange?: (val: string) => void;
}

export function useLeaveRequestFilters({ externalUserId, onExternalUserChange }: UseLeaveRequestFiltersProps = {}) {
    const [pageIndex, setPageIndex] = useState(1);
    const [pageSize, setPageSize] = useState(10);
    const [statusFilter, setStatusFilter] = useState<string>('');
    const [internalUserIdFilter, setInternalUserIdFilter] = useState<string>('');
    const [leaveTypeFilter, setLeaveTypeFilter] = useState<string>('');

    const userIdFilter = externalUserId !== undefined ? externalUserId : internalUserIdFilter;
    const setUserIdFilter = onExternalUserChange || setInternalUserIdFilter;

    const listParams = useMemo<LeaveListParams>(() => {
        const params: LeaveListParams = {
            pageIndex,
            pageSize,
        };

        if (statusFilter !== '') params.status = statusFilter as LeaveStatus;
        if (userIdFilter) params.userProfileId = userIdFilter;
        if (leaveTypeFilter !== '') params.leaveType = leaveTypeFilter as LeaveType;

        return params;
    }, [pageIndex, pageSize, statusFilter, userIdFilter, leaveTypeFilter]);

    const resetFilters = () => {
        setUserIdFilter('');
        setStatusFilter('');
        setLeaveTypeFilter('');
        setPageIndex(1);
    };

    return {
        listParams,
        pageIndex,
        pageSize,
        setPageIndex,
        setPageSize,
        statusFilter,
        setStatusFilter,
        userIdFilter,
        setUserIdFilter,
        leaveTypeFilter,
        setLeaveTypeFilter,
        resetFilters,
    };
}