import { useMutation, useQueryClient } from '@tanstack/react-query';
import { type LeaveBalanceCreateDTO } from '@/api/leaveService';
import { leaveBalanceService } from '@/api/leaveBalanceService';
import { leaveQueryKeys } from '@/features/leave-management/hooks/leaveHooks';
import { getLeaveErrorMessage } from '@/api/leaveService';

export function useLeaveBalanceActions() {
    const queryClient = useQueryClient();

    const createMutation = useMutation({
        mutationFn: (data: LeaveBalanceCreateDTO) => leaveBalanceService.create(data),
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: leaveQueryKeys.all });
        }
    });

    const deleteMutation = useMutation({
        mutationFn: (id: string) => leaveBalanceService.remove(id),
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: leaveQueryKeys.all });
        }
    });

    return {
        createMutation,
        deleteMutation,
        errorMessage: createMutation.error || deleteMutation.error
            ? getLeaveErrorMessage(createMutation.error || deleteMutation.error)
            : null
    };
}
