import React, { useState, useEffect } from 'react';
import { AlertCircle, CheckCircle2, Loader2 } from 'lucide-react';
import { HarmonyDialog } from "@/components/ui/harmony-dialog";
import { Button } from "@/shadcn/components/ui/button";
import HarmonyForm from "@/components/forms/HarmonyForm";
import { leaveService } from '@/api/leaveService';
import { type LeaveCreateForm } from '../types/leave-types';

interface LeaveRequestModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (form: LeaveCreateForm) => void;
  isSubmitting: boolean;
  initialUserId?: string;
}

export const LeaveRequestModal: React.FC<LeaveRequestModalProps> = ({
  isOpen,
  onClose,
  onSubmit,
  isSubmitting,
  initialUserId = '',
}) => {
  const [formKey, setFormKey] = useState(0);
  const [watchedValues, setWatchedValues] = useState({
    UserProfileId: initialUserId,
    LeaveDate: '',
    LeaveSize: 'FullDay',
  });
  const [isValidating, setIsValidating] = useState(false);
  const [balanceStatus, setBalanceStatus] = useState<{ isValid: boolean; message: string } | null>(null);

  // Reset form state when dialog opens
  const [prevIsOpen, setPrevIsOpen] = useState(isOpen);
  if (isOpen !== prevIsOpen) {
    setPrevIsOpen(isOpen);
    if (isOpen) {
      setFormKey(k => k + 1);
      setWatchedValues({ UserProfileId: initialUserId, LeaveDate: '', LeaveSize: 'FullDay' });
      setBalanceStatus(null);
    }
  }

  const { UserProfileId, LeaveDate, LeaveSize } = watchedValues;
  useEffect(() => {
    if (!UserProfileId || !LeaveDate) return;

    const validate = async () => {
      setIsValidating(true);
      try {
        const size = LeaveSize === 'FullDay' ? 1 : 0.5;
        const data = await leaveService.leaves.validateBalance(UserProfileId, LeaveDate, size);
        setBalanceStatus({
          isValid: data.isValid,
          message: data.message || (data.isValid
            ? 'Sufficient balance available for this request.'
            : 'Insufficient balance. This will be marked as Unpaid Leave if approved.'),
        });
      } catch {
        setBalanceStatus(null);
      } finally {
        setIsValidating(false);
      }
    };

    const timer = setTimeout(validate, 500);
    return () => clearTimeout(timer);
  }, [UserProfileId, LeaveDate, LeaveSize]);

  const handleFieldChange = (fieldName: string, value: unknown) => {
    if (fieldName === 'UserProfileId' || fieldName === 'LeaveDate' || fieldName === 'LeaveSize') {
      setWatchedValues(prev => ({ ...prev, [fieldName]: value }));
    }
  };

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const handleSubmit = (formData: any) => {
    onSubmit({
      userProfileId: formData.UserProfileId,
      leaveDate: formData.LeaveDate,
      leaveSize: formData.LeaveSize,
      leaveType: formData.LeaveType,
      reason: formData.Reason,
      notes: formData.Notes || '',
    });
  };

  return (
    <HarmonyDialog
      open={isOpen}
      onOpenChange={onClose}
      title="Request Leave"
      description="Submit a new leave application for review"
      footerChildren={
        <div className="flex justify-end gap-3 w-full">
          <Button variant="secondary" onClick={onClose}>Cancel</Button>
          <Button
            disabled={isSubmitting || isValidating}
            type="button"
            onClick={() => document.querySelector("form")?.requestSubmit?.()}
          >
            {isSubmitting && <Loader2 className="w-4 h-4 animate-spin" />}
            Submit Request
          </Button>
        </div>
      }
    >
      <div className="space-y-6">
        <HarmonyForm
          key={formKey}
          dtoName="LeaveCreateDTO"
          mode="create"
          initialValues={{ UserProfileId: initialUserId }}
          onSubmit={handleSubmit}
          isPending={isSubmitting}
          onFieldChange={handleFieldChange}
          hideSubmitButton
        />

        {watchedValues.UserProfileId && watchedValues.LeaveDate && (
          <div className={`p-4 rounded-[20px] border transition-all duration-300 flex gap-3 ${
            isValidating
              ? 'bg-muted/50 border-border'
              : balanceStatus?.isValid
                ? 'bg-emerald-50/50 dark:bg-emerald-950/20 border-emerald-100 dark:border-emerald-800'
                : 'bg-amber-50/50 dark:bg-amber-950/20 border-amber-100 dark:border-amber-800'
          }`}>
            <div className={`w-8 h-8 rounded-lg flex items-center justify-center shrink-0 ${
              isValidating
                ? 'bg-card text-muted-foreground'
                : balanceStatus?.isValid
                  ? 'bg-emerald-500 text-white'
                  : 'bg-amber-500 text-white'
            }`}>
              {isValidating
                ? <Loader2 className="w-4 h-4 animate-spin" />
                : balanceStatus?.isValid
                  ? <CheckCircle2 className="w-4 h-4" />
                  : <AlertCircle className="w-4 h-4" />}
            </div>
            <div className="min-w-0">
              <p className="text-[11px] font-black text-foreground tracking-tight leading-tight">
                {isValidating ? 'Verifying...' : balanceStatus?.isValid ? 'Balance Verified' : 'Balance Alert'}
              </p>
              <p className="text-[10px] font-medium text-muted-foreground mt-0.5 truncate">
                {isValidating ? 'Checking future entitlements...' : balanceStatus?.message}
              </p>
            </div>
          </div>
        )}
      </div>
    </HarmonyDialog>
  );
};
