import { useState } from 'react';
import { useQueryClient } from '@tanstack/react-query';
import { Button } from '@/shadcn/components/ui/button';
import {
    getLeaveErrorMessage,
} from '@/api/leaveService';
import { leaveQueryKeys, useLeavesListQuery } from '@/features/leave-management/hooks/leaveHooks';
import { Alert, AlertDescription } from '@/shadcn/components/ui/alert';
import { HarmonyAlertDialog } from "@/components/ui/harmony-alert-dialog";
import { ServerPaginationTable } from '@/components/ui/grid/ServerPaginationTable';
import { LeaveFiltersBar } from '../components/LeaveFiltersBar';
import { EditLeaveModal, LeaveDetailModal, RejectLeaveModal } from '../overlays/LeaveOverlays';
import { useLeaveRequestFilters } from '../hooks/useLeaveRequestFilters';
import { useLeaveMutations } from '../hooks/useLeaveMutations';
import { useLeaveColumns } from '../hooks/useLeaveColumns';
import { type LeaveEditForm, type PendingAction } from '../types/leave-types';

interface LeaveRequestsProps {
    externalUserIdFilter?: string;
    onUserIdFilterChange?: (val: string) => void;
    employeeOptions: Array<{ id: string; name: string }>;
}

export default function LeaveRequests({ 
    externalUserIdFilter, 
    onUserIdFilterChange,
    employeeOptions
}: LeaveRequestsProps) {
    const queryClient = useQueryClient();
    const {
        pageIndex,
        pageSize,
        setPageIndex,
        setPageSize,
        statusFilter,
        userIdFilter,
        leaveTypeFilter,
        setStatusFilter,
        setUserIdFilter,
        setLeaveTypeFilter,
        listParams,
        resetFilters,
    } = useLeaveRequestFilters({ 
        externalUserId: externalUserIdFilter, 
        onExternalUserChange: onUserIdFilterChange 
    });

    const [errorMessage] = useState('');
    const [selectedLeaveId, setSelectedLeaveId] = useState<string | null>(null);
    const [editingLeave, setEditingLeave] = useState<LeaveEditForm | null>(null);
    const [rejectTargetId, setRejectTargetId] = useState<string | null>(null);
    const [isRejectModalOpen, setIsRejectModalOpen] = useState(false);
    const [pendingAction, setPendingAction] = useState<PendingAction | null>(null);

    // ── Queries & Mutations ──────────────────────────────────────────────────
    const listQuery = useLeavesListQuery(listParams);

    const { actionMutation, errorMessage: actionError } = useLeaveMutations();



    // ── Logic ────────────────────────────────────────────────────────────────

    const columns = useLeaveColumns({
        onView: setSelectedLeaveId,
        onEdit: (row) => setEditingLeave({
            id: row.id,
            leaveSize: row.leaveSize,
            leaveType: row.leaveType,
            reason: row.reason,
            notes: row.notes ?? '',
        }),
        onApprove: (id) => setPendingAction({
            id, type: 'approve', title: 'Approve Leave', message: 'Move this request to Approved status.', confirmLabel: 'Approve', confirmVariant: 'primary'
        }),
        onReject: (id) => {
            setRejectTargetId(id);
            setIsRejectModalOpen(true);
        },
        onDelete: (id) => setPendingAction({
            id, type: 'delete', title: 'Delete Leave', message: 'Soft-delete this request.', confirmLabel: 'Delete', confirmVariant: 'danger'
        }),
        onConsume: (id) => setPendingAction({
            id, type: 'consumed', title: 'Mark Consumed', message: 'Record balance debit.', confirmLabel: 'Mark Consumed', confirmVariant: 'primary'
        }),
        onNotConsume: (id) => setPendingAction({
            id, type: 'not-consumed', title: 'Mark Not Consumed', message: 'Transition to Not Consumed state.', confirmLabel: 'Mark Not Consumed', confirmVariant: 'warning'
        }),
        onFinalize: (id) => setPendingAction({
            id, type: 'finalize', title: 'Finalize Request', message: 'Finalize the Not Consumed request.', confirmLabel: 'Finalize', confirmVariant: 'primary'
        })
    });

    return (
        <div className="space-y-6">

            {(errorMessage || actionError) && (
                <Alert variant="destructive"><AlertDescription>{errorMessage || actionError}</AlertDescription></Alert>
            )}

            <div className="space-y-6">
                <section className="section-card">
                    <div className="section-card-header">
                        <h3 className="section-card-title">Filters</h3>
                        <Button variant="link" className="h-auto p-0 text-xs font-bold uppercase tracking-widest" onClick={resetFilters}>Reset All</Button>
                    </div>
                    <div className="p-5">
                        <LeaveFiltersBar
                            userIdFilter={userIdFilter}
                            statusFilter={statusFilter}
                            leaveTypeFilter={leaveTypeFilter}
                            employeeOptions={employeeOptions}
                            onUserChange={setUserIdFilter}
                            onStatusChange={setStatusFilter}
                            onTypeChange={setLeaveTypeFilter}
                        />
                    </div>
                </section>

                <section className="section-card no-gap">
                    <ServerPaginationTable
                        columns={columns}
                        rows={listQuery.data?.data ?? []}
                        rowKey={(row) => row.id}
                        isLoading={listQuery.isLoading || actionMutation.isPending}
                        errorMessage={listQuery.error ? getLeaveErrorMessage(listQuery.error) : null}
                        pagination={{
                            pageIndex: listQuery.data?.pageIndex ?? pageIndex,
                            pageSize: listQuery.data?.pageSize ?? pageSize,
                            totalCount: listQuery.data?.totalCount ?? 0,
                            totalPages: listQuery.data?.totalPages ?? 1,
                            hasNextPage: listQuery.data?.hasNextPage ?? false,
                            hasPreviousPage: listQuery.data?.hasPreviousPage ?? false,
                        }}
                        onPageChange={setPageIndex}
                        onPageSizeChange={setPageSize}
                    />
                </section>
            </div>

            {/* Overlays */}
            <LeaveDetailModal id={selectedLeaveId} onClose={() => setSelectedLeaveId(null)} />
            
            <EditLeaveModal 
                data={editingLeave} 
                onClose={() => setEditingLeave(null)} 
                onSuccess={() => queryClient.invalidateQueries({ queryKey: leaveQueryKeys.all })} 
            />

            <RejectLeaveModal
                open={isRejectModalOpen}
                onCancel={() => setIsRejectModalOpen(false)}
                onConfirm={(formData) => {
                    if (rejectTargetId) {
                        actionMutation.mutate({ id: rejectTargetId, type: 'reject', notes: formData.RejectionNotes as string | undefined });
                        setIsRejectModalOpen(false);
                    }
                }}
                isLoading={actionMutation.isPending}
            />

            <HarmonyAlertDialog
                open={Boolean(pendingAction)}
                onOpenChange={(open) => { if (!open) setPendingAction(null); }}
                title={pendingAction?.title ?? ''}
                description={pendingAction?.message ?? ''}
                variant={pendingAction?.confirmVariant === 'primary' ? 'default' : (pendingAction?.confirmVariant ?? 'default') as 'default' | 'warning' | 'danger'}
                actionLabel={pendingAction?.confirmLabel ?? ''}
                onAction={() => {
                    if (pendingAction) {
                        actionMutation.mutate({ id: pendingAction.id, type: pendingAction.type });
                        setPendingAction(null);
                    }
                }}
                isActioning={actionMutation.isPending}
            />
        </div>
    );
}